class Solution:
    def solve(self):
        self.conn = sqlite3.connect(':memory:');
        self.conn.execute('CREATE TABLE products (category TEXT)');
        self.conn.executemany('INSERT INTO products VALUES (?)', [('Electronics',), ('Electronics',), ('Fashion',), ('Fashion',), ('Fashion',), ('Home',), ('Home',), ('Home',), ('Home',)]);
        result = list(self.conn.execute('SELECT DISTINCT category FROM products ORDER BY COUNT(*) DESC, category ASC'));
        self.conn.close();
        return [row[0] for row in result];
